package cmd

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"runtime"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/DocumentDrivenDX/ddx/internal/metaprompt"
	"github.com/DocumentDrivenDX/ddx/internal/registry"
	"github.com/spf13/cobra"
)

const supportedValeVersion = "vale version 3.13.0"

// DiagnosticIssue represents a detected problem and its remediation
type DiagnosticIssue struct {
	Type        string
	Description string
	Remediation []string
	SystemInfo  map[string]string
}

// runDoctor implements the doctor command logic
func (f *CommandFactory) runDoctor(cmd *cobra.Command, args []string) error {
	pathsStr, _ := cmd.Flags().GetString("paths")
	if pathsStr != "" {
		return f.runDoctorScoped(strings.Fields(pathsStr))
	}

	verbose, _ := cmd.Flags().GetBool("verbose")
	applyHousekeeping, _ := cmd.Flags().GetBool("apply")
	fix, _ := cmd.Flags().GetBool("fix")

	fmt.Println("🩺 DDx Installation Diagnostics")
	fmt.Println("=====================================")
	fmt.Println()

	var issues []DiagnosticIssue
	allGood := true
	auditPlugins, _ := cmd.Flags().GetBool("plugins")

	// Check 1: DDX Binary Executable and Install Location
	fmt.Print("✓ Checking DDX Binary... ")
	executable, err := os.Executable()
	if err != nil {
		fmt.Println("❌ Cannot determine executable location")
		allGood = false
	} else {
		fmt.Printf("✅ DDX Binary Executable (%s)\n", executable)
		if locationIssues := checkBinaryInstallLocation(executable); len(locationIssues) > 0 {
			for _, issue := range locationIssues {
				fmt.Printf("   ⚠️  %s\n", issue.Description)
				for _, r := range issue.Remediation {
					fmt.Printf("   💡 %s\n", r)
				}
			}
			issues = append(issues, locationIssues...)
		}
	}

	// Check 2: PATH Configuration
	fmt.Print("✓ Checking PATH Configuration... ")
	if isInPath() {
		fmt.Println("✅ PATH Configuration")
	} else {
		fmt.Println("⚠️  DDX not found in PATH")

		// Check for problem simulation
		problemState := os.Getenv("DDX_PROBLEM_STATE")
		if problemState == "path_issue" || verbose {
			issues = append(issues, DiagnosticIssue{
				Type:        "path_configuration",
				Description: "DDX binary not accessible from PATH",
				Remediation: []string{
					"Run 'ddx setup path'",
					"Restart shell session",
					"Manually add to PATH",
				},
				SystemInfo: map[string]string{
					"shell": os.Getenv("SHELL"),
					"path":  os.Getenv("PATH"),
				},
			})
		}

		if !verbose {
			suggestPathFix()
		}
		// Not marking as failure since DDx is running
	}

	// Check 3: Configuration File
	fmt.Print("✓ Checking Configuration... ")
	if checkConfiguration() {
		fmt.Println("✅ Configuration Valid")
	} else {
		fmt.Println("⚠️  Configuration Issues (non-critical)")
	}

	// Check 3b: Legacy DDx-side model catalog file.
	fmt.Print("✓ Checking Legacy Model Catalog... ")
	if legacyCatalog := checkLegacyModelCatalogFile(); legacyCatalog != nil {
		fmt.Println("⚠️  Legacy DDx-side model catalog found")
		for _, r := range legacyCatalog.Remediation {
			fmt.Printf("   💡 %s\n", r)
		}
		issues = append(issues, *legacyCatalog)
	} else {
		fmt.Println("✅ No legacy DDx-side model catalog file")
	}

	// Check 3c: Pinned Vale prose checker.
	fmt.Print("✓ Checking Prose Checker... ")
	proseCheck := checkProseChecker()
	if proseCheck.Issue == nil {
		fmt.Println("✅ Vale prose checker")
	} else {
		fmt.Println("⚠️  Vale prose checker unavailable or unsupported")
		fmt.Printf("   ⚠️  %s\n", proseCheck.Issue.Description)
		for _, r := range proseCheck.Issue.Remediation {
			fmt.Printf("   💡 %s\n", r)
		}
		issues = append(issues, *proseCheck.Issue)
	}
	if verbose {
		if proseCheck.Path != "" {
			fmt.Printf("   vale path: %s\n", proseCheck.Path)
		}
		if proseCheck.Version != "" {
			fmt.Printf("   vale version: %s\n", proseCheck.Version)
		}
	}

	// Check 4: Git Installation
	fmt.Print("✓ Checking Git... ")
	if checkGit() {
		fmt.Println("✅ Git Available")
	} else {
		fmt.Println("❌ Git Not Found")
		fmt.Println("   Git is required for DDX synchronization features")
		allGood = false
	}

	// Check 4b: Git Repo Health (core.bare / core.worktree / core.hooksPath corruption)
	fmt.Print("✓ Checking Git Repo Health... ")
	repoIssues := checkGitRepoHealth(f.WorkingDir, fix)
	if len(repoIssues) == 0 {
		fmt.Println("✅ Git Repo Clean")
	} else {
		if fix {
			fmt.Printf("🔧 Git Repo Issues Fixed (%d)\n", len(repoIssues))
